#include<bits/stdc++.h>
using namespace std;
const int N=200010;
int n,m,dfn[N],low[N],siz[N*2],scc[N],scccnt,dfncnt;
bool instk[N];
stack<int> s;
vector<int> mp[N],mp1[N*2];
void tarjan(int x)
{
    instk[x]=1;
    s.push(x);
    dfn[x]=low[x]=++dfncnt;
    for(int v:mp[x])
    {
        if(!dfn[v])
        {
            tarjan(v);
            low[x]=min(low[x],low[v]);
        }
        else if(instk[v])
        {
            low[x]=min(low[x],dfn[v]);
        }
    }
    if(low[x]==dfn[x])
    {
        int top;
        scccnt++;
        do
        {
            top=s.top();
            s.pop();
            instk[top]=0;
            scc[top]=scccnt;
            siz[scccnt]++;

        }while(top!=x);
    }
}
int dis[N];
bool vis[N];
int spfa(int x)
{
    stack<int> q;
    // memset(dis,-0x3f,sizeof(dis));
    dis[x]=0;
    q.push(x);
    while(!q.empty())
    {
        int t=q.top();
        q.pop();
        vis[t]=0;
        for(int i:mp1[t])
        {
            if(dis[i]<dis[t]+siz[i])
            {
                dis[i]=dis[t]+siz[i];
                if(!vis[i])
                {
                    vis[i]=1;
                    q.push(i);
                }
            }
        }
    }
    return dis[scccnt+x];
}
int u[N*2],v[N*2];
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        scanf("%d%d",&u[i],&v[i]);
        mp[u[i]].push_back(v[i]);
    }
    for(int i=1;i<=n;i++)
    {
        if(!dfn[i])
        {
            tarjan(i);
        }
    }
    for(int i=1;i<=n;i++)
    {
        for(int j:mp[i])
        {
            if(scc[i]!=scc[j])
            {
                mp1[scc[i]].push_back(scc[j]);
                mp1[scc[i]+scccnt].push_back(scc[j]+scccnt);
                mp1[scc[j]].push_back(scc[i]+scccnt);
            }
        }
    }
    for(int i=1;i<=scccnt;i++)
    {
        siz[scccnt+i]=siz[i];
    }
    mp1[scc[1]].push_back(scc[1]+scccnt);
    printf("%d",spfa(scc[1]));
    return 0;
}
